<section class="container section"><div class="section-title"><h1>Destinos turísticos</h1></div><form class="filters"><input type="hidden" name="route" value="destinations"><input name="search" value="<?=Security::e($search)?>" placeholder="Buscar por nombre o provincia"><button class="btn small">Buscar</button></form><div class="grid"><?php foreach($destinations as $d):?><article class="card"><img src="<?=Security::e($d['image'])?>"><div class="card-body"><small><?=Security::e($d['province'])?></small><h3><?=Security::e($d['name'])?></h3><p><?=Security::e(mb_strimwidth($d['description'],0,150,'...'))?></p><a href="index.php?route=destination&id=<?=$d['id']?>">Conocer destino →</a></div></article><?php endforeach;?></div></section>
